using Microsoft.AspNetCore.Mvc;
using TestNativeMobileBackendApi.Models;
using TestNativeMobileBackendApi.Repositories;

namespace TestNativeMobileBackendApi.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TodosController(ITodoRepository repo) : ControllerBase
{
    [HttpGet]
    public IActionResult List() => Ok(repo.List());

    [HttpGet("{id:guid}")]
    public IActionResult Get(Guid id)
    {
        var item = repo.Get(id);
        if (item is null) return NotFound();
        return Ok(item);
    }

    [HttpPost]
    public IActionResult Create([FromBody] TodoItem item)
    {
        if (item is null) return BadRequest("item is required");
        if (string.IsNullOrWhiteSpace(item.Name)) return BadRequest("Name is required");
        var exists = repo.Get(item.Id) is not null;
        if (exists) return Conflict(new { error = $"todo {item.Id} already exists" });
        repo.Add(item);
        return CreatedAtAction(nameof(Get), new { id = item.Id }, item);
    }

    [HttpPut("{id:guid}")]
    public IActionResult Update(Guid id, [FromBody] TodoItem input)
    {
        var existing = repo.Get(id);
        if (existing is null) return NotFound();
        var updated = input with { Id = id };
        if (string.IsNullOrWhiteSpace(input.Name)) return BadRequest("Name is required");
        var ok = repo.Update(updated);
        if (!ok) return NotFound();
        return Ok(updated);
    }

    [HttpDelete("{id:guid}")]
    public IActionResult Delete(Guid id)
    {
        repo.Delete(id);
        return NoContent();
    }
}

