    private static object ApiError(string code, string message) => new { code, message };

    [HttpGet]
    public IActionResult List() => Ok(repo.List());

    [HttpGet("{id:guid}")]
    public IActionResult Get(Guid id)
    {
        var item = repo.Get(id);
        if (item is null) return NotFound(ApiError("todo_not_found", $"Todo {id} was not found."));
        return Ok(item);
    }

    [HttpPost]
    public IActionResult Create([FromBody] TodoItem item)
    {
        if (item is null) return BadRequest(ApiError("body_required", "Request body is required."));
        if (string.IsNullOrWhiteSpace(item.Name)) return BadRequest(ApiError("name_required", "Name is required."));
        var exists = repo.Get(item.Id) is not null;
        if (exists) return Conflict(ApiError("todo_already_exists", $"Todo {item.Id} already exists."));
        repo.Add(item);
        return CreatedAtAction(nameof(Get), new { id = item.Id }, item);
    }

    [HttpPut("{id:guid}")]
    public IActionResult Update(Guid id, [FromBody] TodoItem input)
    {
        if (string.IsNullOrWhiteSpace(input.Name)) return BadRequest(ApiError("name_required", "Name is required."));
        var existing = repo.Get(id);
        if (existing is null) return NotFound(ApiError("todo_not_found", $"Todo {id} was not found."));
        var updated = input with { Id = id };
        var ok = repo.Update(updated);
        if (!ok) return NotFound(ApiError("todo_not_found", $"Todo {id} was not found."));
        return Ok(updated);
    }

