","newContents":"using Microsoft.AspNetCore.SignalR;

namespace TestSignalRBlazorApp.Hubs;

public class ChatHub : Hub
{
    private const int MaxUserLength = 64;
    private const int MaxMessageLength = 2000;

    public async Task SendMessage(string user, string message)
    {
        var normalizedUser = (user ?? string.Empty).Trim();
        var normalizedMessage = (message ?? string.Empty).Trim();

        if (string.IsNullOrWhiteSpace(normalizedUser))
        {
            throw new HubException("user_required: 'user' must be non-empty.");
        }
        if (string.IsNullOrWhiteSpace(normalizedMessage))
        {
            throw new HubException("message_required: 'message' must be non-empty.");
        }
        if (normalizedUser.Length > MaxUserLength)
        {
            throw new HubException($"user_too_long: 'user' must be <= {MaxUserLength} characters.");
        }
        if (normalizedMessage.Length > MaxMessageLength)
        {
            throw new HubException($"message_too_long: 'message' must be <= {MaxMessageLength} characters.");
        }

        await Clients.All.SendAsync("ReceiveMessage", normalizedUser, normalizedMessage);
    }
}
"})

