tool: EDIT_FILE({"path":"sql/001_initial_schema.sql","oldContents":"","newContents":"-- sql/001_initial_schema.sql
-- Single transaction. Idempotent (IF NOT EXISTS / ON CONFLICT DO NOTHING).
-- Order: lookups first, then items (FK target), then ALTER users to add FKs.

BEGIN;

CREATE TABLE IF NOT EXISTS roles (
    id   SERIAL PRIMARY KEY,
    name VARCHAR(50) NOT NULL UNIQUE
);
INSERT INTO roles (name) VALUES ('admin'), ('user') ON CONFLICT (name) DO NOTHING;

CREATE TABLE IF NOT EXISTS labor_categories (
    id   SERIAL PRIMARY KEY,
    code VARCHAR(20) NOT NULL UNIQUE,
    name VARCHAR(100) NOT NULL
);
INSERT INTO labor_categories (code, name) VALUES
    ('FT',  'Full time'),
    ('PT',  'Part time'),
    ('CON', 'Contractor')
ON CONFLICT (code) DO NOTHING;

CREATE TABLE IF NOT EXISTS item_status (
    id   SERIAL PRIMARY KEY,
    name VARCHAR(50) NOT NULL UNIQUE
);
INSERT INTO item_status (name) VALUES
    ('active'),
    ('inactive'),
    ('archived')
ON CONFLICT (name) DO NOTHING;

-- items references users(id) and item_status(id)
CREATE TABLE IF NOT EXISTS items (
    id            SERIAL PRIMARY KEY,
    name          VARCHAR(255) NOT NULL,
    description   TEXT NULL,
    cost          NUMERIC(12,2) NULL,
    manufacturer  VARCHAR(255) NULL,
    location      VARCHAR(255) NULL,
    owner_user_id INTEGER NULL REFERENCES users(id) ON DELETE SET NULL,
    status_id     INTEGER NOT NULL REFERENCES item_status(id),
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Backfill users FKs added in this migration if they aren't there yet.
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.table_constraints
        WHERE table_name = 'users' AND constraint_name = 'fk_users_role'
    ) THEN
        ALTER TABLE users
            ADD CONSTRAINT fk_users_role
            FOREIGN KEY (role_id) REFERENCES roles(id);
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM information_schema.table_constraints
        WHERE table_name = 'users' AND constraint_name = 'fk_users_labor_category'
    ) THEN
        ALTER TABLE users
            ADD CONSTRAINT fk_users_labor_category
            FOREIGN KEY (labor_category_code) REFERENCES labor_categories(code);
    END IF;
END $$;

COMMIT;
"})

